108	// DefaultDockerSocket is the conventional Docker daemon socket path on Linux and macOS hosts.
109	const DefaultDockerSocket = "/var/run/docker.sock"
110	
111	// defaultDockerSocket is an unexported alias kept for internal use within this package.
112	const defaultDockerSocket = DefaultDockerSocket
113	
114	// socketPathFromDockerContextHost returns the filesystem path when endpoint is a unix:// Docker API URL.
115	func socketPathFromDockerContextHost(endpoint string) (path string, ok bool) {
116		endpoint = strings.TrimSpace(endpoint)
117		if endpoint == "" {
118			return "", false
119		}
120		if !strings.HasPrefix(endpoint, "unix://") {
121			return "", false
122		}
123		path = strings.TrimPrefix(endpoint, "unix://")
124		if path == "" || path[0] != '/' {
125			return "", false
126		}
127		return path, true
128	}
129	
130	func remoteDockerSocketOK(h *host.Host, path string) (bool, error) {
131		q := shellSingleQuote(path)
132		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", q))
133		if err != nil {
134			return false, err
135		}
136		return strings.TrimSpace(out) == "ok", nil
137	}
138	
139	// EffectiveDockerSocket returns the host-side Docker socket path for bind-mounting on Linux and macOS.
140	// When HostConfig.DockerSocket is set, that path is used if it exists. Otherwise gh sr probes, in order:
141	// /var/run/docker.sock, the active docker context unix endpoint (Colima, rootless Docker, etc.),
142	// and on macOS ~/.colima/default/docker.sock.
143	func EffectiveDockerSocket(h *host.Host) (string, error) {
144		if h.OS != "linux" && h.OS != "darwin" {
145			return "", fmt.Errorf("EffectiveDockerSocket: unsupported OS %q", h.OS)
146		}
147		if p := strings.TrimSpace(h.DockerSocket); p != "" {
148			ok, err := remoteDockerSocketOK(h, p)
149			if err != nil {
150				return "", fmt.Errorf("checking docker_socket on host %s: %w", h.Name, err)
151			}
152			if !ok {
153				return "", fmt.Errorf("docker_socket not found or not a socket at %s on host %s", p, h.Name)
154			}
155			return p, nil
156		}
157		ok, err := remoteDockerSocketOK(h, defaultDockerSocket)
158		if err != nil {
159			return "", fmt.Errorf("checking Docker socket on host %s: %w", h.Name, err)
160		}
161		if ok {
162			return defaultDockerSocket, nil
163		}
164		ctxOut, derr := dockerRun(h, `docker context inspect -f '{{.Endpoints.docker.Host}}'`)
165		if derr == nil {
166			if p, parseOK := socketPathFromDockerContextHost(ctxOut); parseOK {
167				ok2, err2 := remoteDockerSocketOK(h, p)
168				if err2 != nil {
169					return "", fmt.Errorf("checking Docker socket from context on host %s: %w", h.Name, err2)
170				}
171				if ok2 {
172					return p, nil
173				}
174			}
175		}
176		if h.OS == "darwin" {
177			out, rerr := h.Run(prependDarwinDockerPATH(h, `p="$HOME/.colima/default/docker.sock"; if test -S "$p"; then printf '%s' "$p"; fi`))
178			if rerr == nil {
179				if p := strings.TrimSpace(out); p != "" {
180					return p, nil
181				}
182			}
183		}
184		hint := "ensure Docker is running (rootless Docker: gh sr uses your default docker context; set docker_socket to override)"
185		if h.OS == "darwin" {
186			hint = "ensure Docker Desktop/OrbStack/Colima is running, or set docker_socket for a non-default socket path"
187		}
188		return "", fmt.Errorf("no usable Docker socket found on host %s; %s", h.Name, hint)
189	}
190	
191	// dockerEngineSockFlags returns the docker run flags needed to expose the host Docker socket inside
192	// a Linux actions-runner container and grant the container's runner user access to it.
193	//
194	// It returns both a -v bind-mount and a --group-add <GID> flag. The GID is read from the host
195	// socket's owning group via `stat -c '%g'`; this avoids "permission denied" when the container's
196	// runner user (uid 1001) is not in the host docker group. If the GID cannot be determined, only
197	// the mount is returned (best-effort; caller may still get EACCES at runtime).
198	//
199	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
200	// The container-side path is always /var/run/docker.sock so job scripts use the default DOCKER_HOST.
201	func dockerEngineSockFlags(h *host.Host, socketPath string) string {
202		if socketPath == "" {
203			socketPath = defaultDockerSocket
204		}
205		mount := fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
206	
207		// Query the GID that owns the socket on the host so we can pass --group-add.
208		out, err := h.Run(fmt.Sprintf("stat -c '%%g' %s 2>/dev/null", socketPath))
209		gid := strings.TrimSpace(out)
210		if err != nil || gid == "" || gid == "0" {
211			// GID 0 means root owns it and no special group; skip --group-add (no benefit or unknown).
212			return mount
213		}
214		return mount + fmt.Sprintf("--group-add %s ", gid)
215	}
216	
217	// darwinDockerBindSourcePath returns the filesystem path to use as the host side of
218	// docker run -v …:/var/run/docker.sock on macOS. Colima exposes the API at
219	// ~/.colima/.../docker.sock on the macOS host, but bind-mounting that path fails with
220	// virtiofs (dockerd mkdir on the socket path: operation not supported; see
221	// https://github.com/abiosoft/colima/issues/997). The same daemon accepts
222	// /var/run/docker.sock (VM-local). Caller must only use this when h.OS == "darwin".
223	func darwinDockerBindSourcePath(resolvedSocket string) string {
224		if resolvedSocket == "" {
225			return resolvedSocket
226		}
227		if strings.Contains(resolvedSocket, "/.colima/") && strings.HasSuffix(resolvedSocket, "docker.sock") {
228			return defaultDockerSocket
229		}
230		return resolvedSocket
231	}
232	
233	// darwinDockerSockFlags returns the docker run flags to bind-mount the Docker socket on a macOS
234	// host. On macOS (Docker Desktop, OrbStack, Colima) the socket is accessible to all processes
235	// inside the VM — there is no docker group GID mismatch — so only the -v mount is needed.
236	//
237	// socketPath is the host-side socket (from HostConfig.DockerSocket, defaulting to /var/run/docker.sock).
238	func darwinDockerSockFlags(socketPath string) string {
239		if socketPath == "" {
240			socketPath = defaultDockerSocket
241		}
242		return fmt.Sprintf("-v %s:/var/run/docker.sock ", socketPath)
243	}
244	
245	// dockerWindowsEngineSockMount is the bind-mount for the Docker engine socket on Windows hosts
246	// (Docker Desktop Linux engine; path is resolved inside the Hyper-V/WSL2 VM).
247	const dockerWindowsEngineSockMount = "-v /var/run/docker.sock:/var/run/docker.sock "
248	
249	// DockerWindowsSockGIDProbeCommand returns the docker CLI line to read the owning GID of
250	// /var/run/docker.sock inside the Docker Desktop Linux engine. Uses sh+stat because the runner
251	// image has no one-shot default CMD suitable for stat.
252	func DockerWindowsSockGIDProbeCommand(image string) string {
253		return fmt.Sprintf(
254			`docker run --rm -v /var/run/docker.sock:/var/run/docker.sock --entrypoint sh %s -c "stat -c '%%g' /var/run/docker.sock"`,
255			image,
256		)
257	}
258	
259	// appendGroupAddForDockerSockGID appends --group-add when probe output is a non-empty numeric GID.
260	// Even GID 0 (root) is added because the docker socket is often owned by root:root on Docker Desktop,
261	// and adding GID 0 as a supplemental group grants the container's runner user access to it.
262	func appendGroupAddForDockerSockGID(mount, gidProbeOutput string) string {
263		gid := strings.TrimSpace(gidProbeOutput)
264		if gid == "" {
265			return mount
266		}
267		for _, c := range gid {
268			if c < '0' || c > '9' {
269				return mount
270			}
271		}
272		return mount + fmt.Sprintf("--group-add %s ", gid)
273	}
274	
275	// dockerEngineSockFlagsWindows returns docker run flags for the Docker socket on a Windows host
276	// running Docker Desktop (Linux containers mode). The socket lives in the Linux engine VM; we
277	// probe its group GID via a disposable container because Windows has no Unix stat on that path.
278	func dockerEngineSockFlagsWindows(h *host.Host) string {
279		out, err := dockerRun(h, DockerWindowsSockGIDProbeCommand(RunnerDockerImage)+` 2>$null`)
280		if err != nil {
281			return dockerWindowsEngineSockMount
282		}
283		return appendGroupAddForDockerSockGID(dockerWindowsEngineSockMount, out)
284	}
285	
286	// dockerEngineSockPreflightCheck verifies the socket path is present and is a socket on the host
287	// before docker run. Returns an error with an actionable message if the socket is missing.
288	func dockerEngineSockPreflightCheck(h *host.Host, socketPath string) error {
289		if socketPath == "" {
290			socketPath = defaultDockerSocket
291		}
292		out, err := h.Run(fmt.Sprintf("test -S %s && echo ok || echo missing", socketPath))
293		if err != nil {
294			return fmt.Errorf("checking Docker socket %s on host: %w", socketPath, err)
295		}
296		if strings.TrimSpace(out) != "ok" {
297			msg := fmt.Sprintf(
298				"Docker socket not found at %s on host %s; ensure Docker is installed and running (or set docker_socket in config for rootless Docker)",
299				socketPath, h.Name,
300			)
301			return fmt.Errorf("%s", msg)
302		}
303		return nil
304	}
305	
306	// prependDarwinDockerPATH prefixes a remote shell command on macOS so the Docker CLI is on PATH
307	// when SSH uses a minimal environment (missing /usr/local/bin and /opt/homebrew/bin).
308	func prependDarwinDockerPATH(h *host.Host, cmd string) string {
309		if h.OS != "darwin" {
310			return cmd
311		}
312		return `export PATH="/usr/local/bin:/opt/homebrew/bin:$PATH"; ` + cmd
313	}
314	
315	// dockerRun executes a Docker CLI command on the host, using PowerShell
316	// wrapping on Windows and raw shell on Linux/macOS.
317	func dockerRun(h *host.Host, cmd string) (string, error) {
318		if h.OS == "windows" {
319			return h.RunShell(windowsDockerCommand(cmd))
320		}
321		return h.Run(prependDarwinDockerPATH(h, cmd))
322	}
323	
324	// dockerRunIgnoreErr is like dockerRun but discards the error (for best-effort cleanup).
325	func dockerRunIgnoreErr(h *host.Host, cmd string) {
326		if h.OS == "windows" {
327			h.RunShell(windowsDockerCommand(cmd))
328		} else {
329			h.Run(prependDarwinDockerPATH(h, cmd))
330		}
331	}
332	
333	func (m *Manager) setupDocker(h *host.Host) error {
334		if h.OS == "windows" {
335			return m.setupDockerWindows(h)
336		}
337		return m.setupDockerUnix(h)
338	}
339	
340	// windowsDockerCommand forces Docker to use an isolated config directory that
341	// avoids the Windows native credential helper in SSH sessions. The dummy auth
342	// entry keeps Docker CLI from auto-detecting wincred as the default store when
343	// no auth is configured.
344	func windowsDockerCommand(cmd string) string {
345		return strings.TrimSpace(fmt.Sprintf(`
346	$ghsrDockerConfigDir = Join-Path $env:TEMP 'gh-sr-docker-config'
347	New-Item -ItemType Directory -Force -Path $ghsrDockerConfigDir | Out-Null
348	$ghsrDockerConfigFile = Join-Path $ghsrDockerConfigDir 'config.json'
349	$ghsrDockerConfigJson = @'
350	{
351	  "auths": {
352	    "ghsr.invalid": {
353	      "auth": "Z2hyOmdocg=="
354	    }
355	  },
356	  "credsStore": ""
357	}
358	'@
359	[System.IO.File]::WriteAllText($ghsrDockerConfigFile, $ghsrDockerConfigJson, [System.Text.UTF8Encoding]::new($false))
360	$env:DOCKER_CONFIG = $ghsrDockerConfigDir
361	%s
362	`, cmd))
363	}
364	
365	func (m *Manager) setupDockerWindows(h *host.Host) error {
366		out, err := dockerRun(h, `docker info --format "{{.ServerVersion}}"`)
367		if err != nil || strings.TrimSpace(out) == "" {
368			return fmt.Errorf("docker not available on host %s: install Docker Desktop and ensure it is running", h.Name)
369		}
370		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, strings.TrimSpace(out))
371	
372		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
373		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
374			return fmt.Errorf("pulling Docker image: %w", err)
375		}
376	
377		return nil
378	}
