429	func (m *Manager) setupDockerUnix(h *host.Host) error {
430		hasCLI, err := UnixDockerCLIInstalled(h)
431		if err != nil {
432			return fmt.Errorf("checking docker on host %s: %w", h.Name, err)
433		}
434	
435		if hasCLI {
436			out, verr := UnixDockerServerVersion(h)
437			if verr == nil {
438				fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
439				fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
440				if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
441					return fmt.Errorf("pulling Docker image: %w", err)
442				}
443				return nil
444			}
445			if h.OS == "darwin" {
446				return fmt.Errorf(
447					"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session: %w",
448					h.Name, verr,
449				)
450			}
451			return fmt.Errorf("docker on host %s is not usable: %w", h.Name, verr)
452		}
453	
454		if h.OS == "darwin" {
455			return fmt.Errorf(
456				"docker not available on host %s: install Docker Desktop, OrbStack, or Colima and ensure the Docker CLI works in your SSH session",
457				h.Name,
458			)
459		}
460	
461		fmt.Fprintf(m.out(), "  %s: Docker not found, attempting to install...\n", h.Name)
462		installCmd := linuxElevatePrelude + `
463				if ! command -v curl >/dev/null 2>&1; then
464					if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl;
465					elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl;
466					elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl;
467					fi
468				fi &&
469				curl -fsSL https://get.docker.com | $SUDO sh
470			`
471		if _, instErr := h.Run(installCmd); instErr != nil {
472			return fmt.Errorf(
473				"failed to install docker on host %s (need root SSH, passwordless sudo, or install Docker manually; see gh sr doctor): %w",
474				h.Name, instErr,
475			)
476		}
477	
478		hasCLI, err = UnixDockerCLIInstalled(h)
479		if err != nil {
480			return fmt.Errorf("rechecking docker on host %s: %w", h.Name, err)
481		}
482		if !hasCLI {
483			return fmt.Errorf("docker still not installed on host %s after installation attempt", h.Name)
484		}
485		out, verr := UnixDockerServerVersion(h)
486		if verr != nil {
487			return fmt.Errorf("docker installed on host %s but still not usable (e.g. add user to 'docker' group and reconnect SSH): %w", h.Name, verr)
488		}
489		fmt.Fprintf(m.out(), "  %s: Docker %s available\n", h.Name, out)
490	
491		fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", h.Name)
492		if _, err := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); err != nil {
493			return fmt.Errorf("pulling Docker image: %w", err)
494		}
495	
496		return nil
497	}
