499	func (m *Manager) startDocker(h *host.Host, rc config.RunnerConfig, instanceName string) error {
500		cname := containerName(instanceName)
501	
502		if h.OS == "windows" {
503			running, _ := dockerRun(h, fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname))
504			if strings.TrimSpace(running) == "true" {
505				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
506				return nil
507			}
508			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>$null", cname))
509		} else {
510			running, _ := dockerRun(h, fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname))
511			if strings.TrimSpace(running) == "true" {
512				fmt.Fprintf(m.out(), "  %s: already running\n", instanceName)
513				return nil
514			}
515			dockerRunIgnoreErr(h, fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname))
516		}
517	
518		// Auto-pull image if not present locally.
519		imgCheck := fmt.Sprintf("docker images -q %s", RunnerDockerImage)
520		if h.OS == "windows" {
521			imgCheck += " 2>$null"
522		} else {
523			imgCheck += " 2>/dev/null"
524		}
525		imgOut, _ := dockerRun(h, imgCheck)
526		if strings.TrimSpace(imgOut) == "" {
527			fmt.Fprintf(m.out(), "  %s: pulling runner image...\n", instanceName)
528			if _, pullErr := dockerRun(h, fmt.Sprintf("docker pull %s", RunnerDockerImage)); pullErr != nil {
529				return fmt.Errorf("pulling Docker image for %s: %w", instanceName, pullErr)
530			}
531		}
532	
533		regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
534		if err != nil {
535			return err
536		}
537	
538		labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
539		var repoURL string
540		if rc.Org != "" {
541			repoURL = fmt.Sprintf("https://github.com/%s", rc.Org)
542		} else {
543			repoURL = fmt.Sprintf("https://github.com/%s", rc.Repo)
544		}
545	
546		var sockFlags string
547		switch h.OS {
548		case "linux", "darwin":
549			sockPath, err := EffectiveDockerSocket(h)
550			if err != nil {
551				return err
552			}
553			if h.OS == "linux" {
554				sockFlags = dockerEngineSockFlags(h, sockPath)
555			} else {
556				sockFlags = darwinDockerSockFlags(darwinDockerBindSourcePath(sockPath))
557			}
558		case "windows":
559			// Docker Desktop (Linux containers mode): bind-mount the engine socket and match Linux
560			// behavior by adding --group-add for the socket's GID when we can probe it from a disposable container.
561			sockFlags = dockerEngineSockFlagsWindows(h)
562		}
563	
564		cmd := dockerStartCommand(dockerStartOpts{
565			ContainerName: cname,
566			InstanceName:  instanceName,
567			RegToken:      regToken,
568			RepoURL:       repoURL,
569			Labels:        labels,
570			SockMount:     sockFlags,
571			Image:         RunnerDockerImage,
572			NetworkMode:   rc.EffectiveDockerNetworkMode(h.OS),
573			CapAdds:       rc.DockerCapAdd,
574			RunnerGroup:   rc.Group,
575			Ephemeral:     rc.Ephemeral,
576		})
577	
578		out, err := dockerRun(h, cmd)
579		if err != nil {
580			return fmt.Errorf("starting Docker container: %w", err)
581		}
582	
583		containerID := strings.TrimSpace(out)
584		if len(containerID) > 12 {
585			containerID = containerID[:12]
586		}
587		fmt.Fprintf(m.out(), "  %s: started (container %s)\n", instanceName, containerID)
588		return nil
589	}
590	
591	func (m *Manager) stopDocker(h *host.Host, instanceName string) error {
592		cname := containerName(instanceName)
593	
594		var inspectCmd string
595		if h.OS == "windows" {
596			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname)
597		} else {
598			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname)
599		}
600		running, _ := dockerRun(h, inspectCmd)
601		if strings.TrimSpace(running) != "true" {
602			fmt.Fprintf(m.out(), "  %s: not running\n", instanceName)
603			return nil
604		}
605	
606		if _, err := dockerRun(h, fmt.Sprintf("docker stop -t 30 %s", cname)); err != nil {
607			return fmt.Errorf("stopping container: %w", err)
608		}
609	
610		fmt.Fprintf(m.out(), "  %s: stopped\n", instanceName)
611		return nil
612	}
613	
614	func (m *Manager) removeDocker(h *host.Host, instanceName string) error {
615		cname := containerName(instanceName)
616	
617		_ = m.stopDocker(h, instanceName)
618	
619		var rmCmd string
620		if h.OS == "windows" {
621			rmCmd = fmt.Sprintf("docker rm -f %s 2>$null", cname)
622		} else {
623			rmCmd = fmt.Sprintf("docker rm -f %s 2>/dev/null || true", cname)
624		}
625		if _, err := dockerRun(h, rmCmd); err != nil {
626			return fmt.Errorf("removing container: %w", err)
627		}
628	
629		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
630		return nil
631	}
632	
633	func (m *Manager) statusDocker(h *host.Host, instanceName string) string {
634		cname := containerName(instanceName)
635	
636		var inspectCmd string
637		if h.OS == "windows" {
638			inspectCmd = fmt.Sprintf(`docker inspect -f "{{.State.Status}}" %s 2>$null`, cname)
639		} else {
640			inspectCmd = fmt.Sprintf("docker inspect -f '{{.State.Status}}' %s 2>/dev/null", cname)
641		}
642		out, err := dockerRun(h, inspectCmd)
643		if err != nil {
644			return "not installed"
645		}
646	
647		status := strings.TrimSpace(out)
648		switch status {
649		case "running":
650			return "running"
651		case "exited", "dead", "created":
652			return "stopped"
653		default:
654			return status
655		}
656	}
657	
658	func (m *Manager) logsDocker(h *host.Host, instanceName string) (string, error) {
659		cname := containerName(instanceName)
660		cmd := fmt.Sprintf("docker logs --tail 50 %s 2>&1", cname)
661		return dockerRun(h, cmd)
662	}
